import json
import hashlib
import os
import threading
import time
import functools


class DiskCache:
    """Disk-backed callable cache with TTL expiry and JSON persistence.

    Can be used directly as a decorator on functions::

        cache = DiskCache(cache_dir="./cache", ttl=3600)

        @cache
        def my_func(x: int) -> int:
            return x * 2
    """

    def __init__(self, cache_dir: str = "./cache", ttl: int = 3600) -> None:
        self.cache_dir = cache_dir
        self.ttl = ttl
        self._lock = threading.Lock()

    # ── cache key helpers ──────────────────────────────────────────────

    def _make_key(self, func, args, kwargs) -> str:
        """Deterministic, filesystem-safe key from function name and
        the repr of all positional / keyword arguments (handles unhashable
        types like ``list`` or ``dict``)."""
        parts = [func.__name__, repr(args), repr(kwargs)]
        raw = "".join(parts).encode("utf-8")
        return hashlib.sha256(raw).hexdigest()

    def _cache_path(self, key: str) -> str:
        return os.path.join(self.cache_dir, f"{key}.json")

    # ── cache I/O helpers ──────────────────────────────────────────────

    def _load(self, path: str):
        """Return deserialised JSON content or *None* on failure."""
        try:
            with open(path, "r") as f:
                return json.load(f)
        except (json.JSONDecodeError, OSError):
            return None

    def _is_fresh(self, path: str) -> bool:
        """Return ``True`` when the file is still within its TTL window.

        A TTL of 0 means *never expire*.
        """
        if self.ttl == 0:
            return True
        try:
            age = time.time() - os.path.getmtime(path)
            return age <= self.ttl
        except OSError:
            return False

    # ── decorator protocol ─────────────────────────────────────────────

    def __call__(self, func):
        """Return a wrapper that caches ``func`` results on disk."""

        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            key = self._make_key(func, args, kwargs)
            path = self._cache_path(key)

            # 1. Try cache hit -------------------------------------------------
            with self._lock:
                if os.path.isfile(path) and self._is_fresh(path):
                    cached = self._load(path)
                    if cached is not None:
                        return cached

            # 2. Miss -- compute and persist ----------------------------------
            result = func(*args, **kwargs)

            os.makedirs(self.cache_dir, exist_ok=True)
            with self._lock:
                with open(path, "w") as f:
                    json.dump(result, f)

            return result

        # Expose cache management on the decorated function.
        wrapper.clear = self.clear
        return wrapper

    # ── cache management ─────────────────────────────────────────────────

    def clear(self) -> None:
        """Remove every ``*.json`` file inside *cache_dir*."""
        with self._lock:
            if not os.path.isdir(self.cache_dir):
                return
            for name in os.listdir(self.cache_dir):
                path = os.path.join(self.cache_dir, name)
                if name.endswith(".json") and os.path.isfile(path):
                    os.remove(path)


def disk_cache(cache_dir: str = "./cache", ttl: int = 3600):
    """Convenience factory for ``DiskCache``.

    Usage::

        @disk_cache(cache_dir="./cache", ttl=3600)
        def my_function(x: int) -> int:
            return x * 2
    """
    return DiskCache(cache_dir=cache_dir, ttl=ttl)
